section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/refactor-baseline-metrics-script.json",
  "type": "object",
  "title": "Refactor Baseline Metrics Script",
  "required": [
    "baseline_id",
    "branch",
    "loc",
    "cyclomatic_avg",
    "hotspot_commits_90d",
    "test_runtime_sec",
    "coverage_pct",
    "hotspot_window_days"
  ],
  "additionalProperties": false,
  "properties": {
    "baseline_id": {
      "type": "string",
      "minLength": 1,
      "description": "Run identifier."
    },
    "branch": {
      "type": "string",
      "minLength": 1,
      "description": "Git ref measured."
    },
    "loc": {
      "type": "integer",
      "description": "Lines of code in the changed scope."
    },
    "cyclomatic_avg": {
      "type": "number",
      "description": "Average cyclomatic complexity in scope."
    },
    "hotspot_commits_90d": {
      "type": "integer",
      "description": "Commits touching scope in last 90d."
    },
    "test_runtime_sec": {
      "type": "number",
      "description": "Test runtime in seconds."
    },
    "coverage_pct": {
      "type": "number",
      "description": "Coverage percentage; 0-1."
    },
    "hotspot_window_days": {
      "type": "integer",
      "description": "Window used; default 90."
    }
  }
}
